"use strict";(()=>{const t=()=>{if(window.matchMedia("(pointer: coarse)").matches||window.matchMedia("(prefers-reduced-motion: reduce)").matches)return;const n=document.querySelectorAll(".glass-panel");if(n.length===0)return;let o=-9999,s=-9999;const c=()=>{for(const e of n){const r=e.getBoundingClientRect();e.style.setProperty("--glow-x",`${o-r.left}px`),e.style.setProperty("--glow-y",`${s-r.top}px`)}};document.addEventListener("mousemove",e=>{o=e.clientX,s=e.clientY,c()})};document.readyState==="loading"?document.addEventListener("DOMContentLoaded",t):t()})();
